60	    mutation.mutate({
61	      payload: {
62	        accountId: session.accountId,
63	        variableId: market.variableId,
64	        target: { kind: "marginal", outcomeId, probability },
65	        context: validContext,
66	        idempotencyKey: crypto.randomUUID(),
67	      },
68	      session,
69	    });
70	  };
71	
72	  const hasContext = context.length > 0;
73	
74	  return (
75	    <div style={panelStyle}>
76	      <h3 style={{ fontSize: "1rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>
